import{_ as e,o as a,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const g=JSON.parse('{"title":"皇穹宇与回音壁","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/temple-of-heaven/huangqiong-yu.md","filePath":"landmarks/temple-of-heaven/huangqiong-yu.md","lastUpdated":1784720050000}'),n={name:"landmarks/temple-of-heaven/huangqiong-yu.md"};function r(i,t,d,s,h,u){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="皇穹宇与回音壁" tabindex="-1">皇穹宇与回音壁 <a class="header-anchor" href="#皇穹宇与回音壁" aria-label="Permalink to &quot;皇穹宇与回音壁&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1590520623494-2ec1cc752900?w=1200&amp;q=80" alt="皇穹宇"></p><blockquote><p>&quot;一堵圆墙藏声韵，轻声贴壁可传情。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>皇穹宇位于圜丘坛以北，是一座小巧而庄严的圆形殿宇，始建于明嘉靖九年（1530年），初名&quot;泰神殿&quot;，嘉靖十七年改称&quot;皇穹宇&quot;。它的功能是<strong>供奉祭天神牌</strong>——平时，&quot;皇天上帝&quot;及诸配祀神牌安放于此，冬至大祀时再迎请至<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>受祭。</p><p>皇穹宇殿身圆形、单檐蓝瓦攒尖顶，鎏金宝顶，高约19.5米，直径约15.6米，形制宛如缩小的<a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a>，象征&quot;天&quot;的圆融。</p><p>然而让皇穹宇名扬天下的，并非殿宇本身，而是环绕它的那道圆形围墙——<strong>回音壁</strong>，以及殿前的<strong>三音石</strong>。这两处声学奇观与圜丘的天心石并称&quot;天坛三音&quot;，是古代建筑工艺与物理现象的美妙巧合。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><p><img src="https://images.unsplash.com/photo-1665723296765-16db488e23dd?w=1200&amp;q=80" alt="皇穹宇穹顶"></p><h3 id="回音壁" tabindex="-1">回音壁 <a class="header-anchor" href="#回音壁" aria-label="Permalink to &quot;回音壁&quot;">​</a></h3><p>皇穹宇的圆形围墙高约3.7米，周长193米，以磨砖对缝工艺砌筑，墙面光洁平滑、弧度规整。<strong>声波可以贴着墙面连续折射传播</strong>，衰减极小：两人分立于围墙的东西两端，一人面墙轻声说话，另一人将耳朵贴近墙面，即可清晰听见，犹如打电话一般。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">规格</th></tr></thead><tbody><tr><td style="text-align:left;">围墙形状</td><td style="text-align:left;">正圆形</td></tr><tr><td style="text-align:left;">墙高</td><td style="text-align:left;">约3.7米</td></tr><tr><td style="text-align:left;">周长</td><td style="text-align:left;">193米</td></tr><tr><td style="text-align:left;">砌筑工艺</td><td style="text-align:left;">磨砖对缝，墙面平滑</td></tr><tr><td style="text-align:left;">声学原理</td><td style="text-align:left;">声波沿光滑弧面连续反射传播</td></tr><tr><td style="text-align:left;">现状</td><td style="text-align:left;">墙根设保护围栏，贴墙通话已难实现</td></tr></tbody></table><p>需要留意的是：回音壁院内如今植有古柏，墙根亦设有保护围栏，游客已无法真正贴墙对话，<strong>回音效果较以往明显减弱</strong>，不妨以想象补足昔日的奇趣。</p><p>不过，只要避开人流高峰、贴近墙面轻声一试，仍有机会捕捉到声波环壁而来的微弱回响——这份&quot;半隐半现&quot;的奇趣，反倒比一览无余更耐寻味。</p><h3 id="无梁殿结构" tabindex="-1">无梁殿结构 <a class="header-anchor" href="#无梁殿结构" aria-label="Permalink to &quot;无梁殿结构&quot;">​</a></h3><p>皇穹宇殿内穹顶<strong>不设横梁</strong>，完全由层层收分的斗拱与枋木支撑而成，结构精巧，是著名的&quot;无梁殿&quot;式做法。殿内供奉皇天上帝神牌，正中设神龛，东西配殿（东西庑）供奉日月星辰、云雨风雷诸神牌。</p><h3 id="三音石" tabindex="-1">三音石 <a class="header-anchor" href="#三音石" aria-label="Permalink to &quot;三音石&quot;">​</a></h3><p>殿前石板甬道上，自殿门向南的第三块石板即为著名的&quot;三音石&quot;：立于其上击掌或呼唤，可听到两三次清晰的回音——声波被圆形围墙反射回来，一次回返一声。相传站在不同位置，回声有一声、两声、三声之别，故称&quot;三音石&quot;。</p><p>三音石的位置恰在圆墙的几何中心：声波向四面八方传开，碰到弧墙后同时折返，在中心点汇合，于是每一次回返都清晰可辨。天心石取其&quot;聚&quot;，回音壁取其&quot;传&quot;，三音石取其&quot;返&quot;——&quot;天坛三音&quot;各擅胜场，共同构成一组完整的声学奇观。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="神牌的-居所" tabindex="-1">神牌的&quot;居所&quot; <a class="header-anchor" href="#神牌的-居所" aria-label="Permalink to &quot;神牌的&quot;居所&quot;&quot;">​</a></h3><p>在明清礼制中，天坛诸神牌平日即&quot;居住&quot;在皇穹宇：冬至大祀前，太常寺官员斋戒奉请神牌，以龙亭迎至圜丘坛；礼成后再奉安回殿。一座小殿，牵动一年中最隆重的国家典礼的起止。</p><h3 id="从-泰神-到-皇穹" tabindex="-1">从&quot;泰神&quot;到&quot;皇穹&quot; <a class="header-anchor" href="#从-泰神-到-皇穹" aria-label="Permalink to &quot;从&quot;泰神&quot;到&quot;皇穹&quot;&quot;">​</a></h3><p>皇穹宇初名&quot;泰神殿&quot;。&quot;泰&quot;取尊极之意，而嘉靖帝后来改定&quot;皇穹宇&quot;之名——&quot;皇&quot;言其尊，&quot;穹&quot;言天如穹庐覆下，&quot;宇&quot;言其为屋宇——一字一名，皆是帝王对&quot;天&quot;的想象与敬意。</p><h3 id="回音壁的-被发现" tabindex="-1">回音壁的&quot;被发现&quot; <a class="header-anchor" href="#回音壁的-被发现" aria-label="Permalink to &quot;回音壁的&quot;被发现&quot;&quot;">​</a></h3><p>回音壁的回音现象并非营建时的刻意设计，而是磨砖对缝的精密工艺&quot;无心插柳&quot;的产物。清代文献中少见记载，直到近现代，这一声学奇观才被游人广泛发现并口耳相传，与天心石、三音石一起并称&quot;天坛三音&quot;，成为天坛最富趣味的游赏记忆。</p><h2 id="最佳游览季节" tabindex="-1">最佳游览季节 <a class="header-anchor" href="#最佳游览季节" aria-label="Permalink to &quot;最佳游览季节&quot;">​</a></h2><p>皇穹宇院落不大，四时皆宜，但<strong>清晨开门时段</strong>体验最佳：游客稀少、院中静谧，立于回音壁内环视圆殿，最能感受皇家禁地的肃穆。秋日院内古柏与蓝瓦相映，色温冷暖相宜，是摄影的黄金期。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>回音壁圆墙</strong>：观察磨砖对缝的墙面工艺，想象声波环壁而传的奇观。</li><li><strong>三音石听回声</strong>：在殿前甬道找到三音石（地面有标识），击掌试听回音。</li><li><strong>无梁穹顶</strong>：入殿仰观斗拱层叠、无梁自承的木构奇技。</li><li><strong>神龛陈设</strong>：殿内皇天上帝神牌与神龛复原陈列，是理解祭祀体系的实物。</li><li><strong>袖珍版祈年殿</strong>：远观皇穹宇的蓝瓦金顶轮廓，与祈年殿遥相呼应。</li><li><strong>&quot;天坛三音&quot;集齐</strong>：三音石（本院）、天心石（<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>）、回音壁（本院），一处集齐其二。</li></ol><h2 id="最佳拍照点" tabindex="-1">最佳拍照点 <a class="header-anchor" href="#最佳拍照点" aria-label="Permalink to &quot;最佳拍照点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">机位</th><th style="text-align:left;">画面</th><th style="text-align:left;">建议时间</th></tr></thead><tbody><tr><td style="text-align:left;">南棂星门内中轴线</td><td style="text-align:left;">圆殿居中、围墙环抱的经典构图</td><td style="text-align:left;">上午顺光</td></tr><tr><td style="text-align:left;">回音壁墙根低角度</td><td style="text-align:left;">弧墙一线天，突出墙面工艺</td><td style="text-align:left;">人少时段</td></tr><tr><td style="text-align:left;">三音石处回望殿门</td><td style="text-align:left;">甬道纵深感</td><td style="text-align:left;">全天</td></tr><tr><td style="text-align:left;">院外古柏旁</td><td style="text-align:left;">蓝瓦金顶与柏枝相映</td><td style="text-align:left;">清晨或日落</td></tr></tbody></table><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>位置居中</strong>：皇穹宇介于<a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>与<a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>之间，是精华路线的必经节点。</li><li><strong>回音壁现状</strong>：受围栏和树木影响，贴墙通话已难实现，不必过度期待，重点欣赏建筑工艺。</li><li><strong>三音石勿拥堵</strong>：试听回音时留意周围游客，避开高峰时段体验更佳。</li><li><strong>东西配殿别漏看</strong>：配殿陈列神牌与祭器，内容充实且游客较少。</li><li><strong>安静时感受最好</strong>：清晨人少时立于院内，最能体会皇家禁地的肃穆氛围。</li><li><strong>绕墙一周</strong>：沿回音壁内侧缓行一圈（约193米），边走边看墙面磨砖工艺，方能体会&quot;声学奇迹&quot;背后的建筑功底。</li></ol><h2 id="相关景点" tabindex="-1">相关景点 <a class="header-anchor" href="#相关景点" aria-label="Permalink to &quot;相关景点&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/huanqiu-tan.html">圜丘坛</a>：皇穹宇正南，神牌冬至迎请受祭之所</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/danbi-qiao.html">丹陛桥</a>：院北即神路起点，由此北望祈年殿</li><li><a href="/beijing-travel-guide/landmarks/temple-of-heaven/qinian-dian.html">祈年殿</a>：与皇穹宇形制相仿的三重檐圆殿</li></ul><hr><p><strong>📍 位置</strong>：天坛内坛南部，圜丘坛正北 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/temple-of-heaven/">天坛概览</a></p>',38)])])}const f=e(n,[["render",r]]);export{g as __pageData,f as default};
